INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L1_A', 'D1', 1, 'A', 'Physical manipulation', '30-50 small objects (beans, sticks), rubber bands or small cups', 'Give your child 34 objects. Ask them: ''How can we count these quickly without losing track?'' Let them try. If they don''t group by 10s, suggest: ''What if we put them in groups of 10?''', 'Child groups objects into 10s and counts the leftover ones.', 'Child insists on counting by 1s and loses track, or cannot form a group of 10.', 'Why is grouping by 10 faster than counting by 1?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L1_B', 'D1', 1, 'B', 'Physical manipulation', '30-50 blocks or beads, small containers', 'Give your child 42 objects. Say: ''We need to count these, but my eyes get tired counting one by one. Can you find a way to make little groups so it is easier to see how many we have?''', 'Child makes consistent groups (ideally 10s) and identifies the total by counting groups.', 'Child makes random sized groups or continues to count by ones.', 'Why did you choose to put that many in each group? Does it make counting faster?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L1_C', 'D1', 1, 'C', 'Physical manipulation', '40-50 bottle caps, small bags', 'Scatter 48 objects on the floor. Ask: ''Imagine you have to tell me how many there are in 5 seconds. How can we organize them so we can count them super fast?''', 'Child organizes items into piles of 10 for quick counting.', 'Child leaves them scattered and points one by one.', 'How does putting them in groups help us not make mistakes?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L2_A', 'D1', 2, 'A', 'Physical to symbolic translation', 'Bundles of 10, single objects, paper', 'Tell your child to build the number 42. Watch if they use the bundles correctly.', 'Correctly represents the number with tens and ones. Handles the endurance ''unbundling'' task.', 'Reverses tens and ones, or counts out 42 individual items.', 'If I have 2 bundles of 10 and 15 loose beans, what number is that? How do you know?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L2_B', 'D1', 2, 'B', 'Physical to symbolic translation', 'Sticks bundled in 10s, loose sticks', 'Ask your child to show you the number 65 using the bundles and loose sticks, then write the number down.', 'Selects 6 bundles and 5 loose sticks, writing ''65''.', 'Writes ''605'' or ''56''.', 'If you drop one bundle, what number do you have now?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L2_C', 'D1', 2, 'C', 'Physical to symbolic translation', '10-frames drawn on paper, counters', 'Ask your child to fill 10-frames to show the number 53.', 'Fills 5 complete 10-frames and puts 3 counters in the 6th frame.', 'Only fills 5 counters total and 3 counters total.', 'Why don''t we just count out 53 counters without the frames?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L3_A', 'D1', 3, 'A', 'Error detection', NULL, 'Show your child this drawing: 3 bundles of 10 and 12 loose sticks. Say: ''Your friend wrote that this is the number 3012. Is that right? What should it be?''', 'Identifies that 10 loose sticks make a new bundle, so it''s 4 bundles and 2 sticks = 42.', 'Agrees with 3012, treating tens and ones as separate numbers rather than a combined quantity.', 'Can you ever have 12 single ones in the ''ones'' place? Why not?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L3_B', 'D1', 3, 'B', 'Error detection', NULL, 'Show your child a paper that says: ''5 tens and 14 ones = 64''. Ask: ''Is this math right? How did they get 64 from 5 and 14?''', 'Explains that 14 ones is one ten and four ones, so 5 tens + 1 ten = 6 tens, making 64.', 'Says it is wrong because 5+14 is 19.', 'What happens when the ''ones'' pile gets to be 10 or more?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L3_C', 'D1', 3, 'C', 'Error detection', NULL, 'Say: ''Someone tried to build 45. They used 5 bundles of ten and 4 loose sticks. Did they do it right?''', 'Recognizes they built 54 instead of 45 by swapping the tens and ones.', 'Agrees they built 45.', 'Why does it matter which number is the bundles and which is the loose sticks?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L4_A', 'D1', 4, 'A', 'System design', NULL, 'Ask your child: ''If we were aliens with only 4 fingers on each hand, how would we bundle our sticks? Show me what the number 23 would look like for them.''', 'Child bundles by 8s (or 4s). Realizes that ''10'' is just a convention, not a magic number.', 'Cannot conceptualize grouping by anything other than 10.', 'Can you prove that base-8 works the same way as base-10? What''s the rule that all bases share?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L4_B', 'D1', 4, 'B', 'System design', NULL, 'Say: ''Imagine a factory that packs boxes of biscuits. But they only pack them in boxes of 6. How would they write down that they have 15 biscuits?''', 'Shows they have 2 boxes and 3 loose biscuits (like base 6).', 'Tries to force them into groups of 10.', 'If they had 6 boxes of 6, what would they need to do next?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L4_C', 'D1', 4, 'C', 'System design', NULL, 'Ask: ''Design a money system for a new country where you only have 5-coin coins and 1-coin coins. How would you pay for something that costs 17?''', 'Uses three 5-coins and two 1-coins.', 'Just uses seventeen 1-coins without grouping.', 'What is the biggest number of 1-coins you would ever need to carry in your pocket in this country?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L1_A', 'D2', 1, 'A', 'Physical storytelling', 'Two disparate groups of items (e.g., 7 rocks, 5 leaves)', 'Present 7 rocks and 5 leaves. Ask: ''If we put all of these into one big pile, how many things do we have total? Don''t count from 1. Can you start from the bigger group?''', 'Starts with 7 and counts on: ''8, 9, 10, 11, 12''. Understands addition is joining.', 'Counts every item starting from 1.', 'Does it matter if we start with the rocks or the leaves? Why?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L1_B', 'D2', 1, 'B', 'Physical storytelling', '8 spoons, 4 forks', 'Show 8 spoons in one hand and 4 forks in the other. Ask: ''If I put all these in the washing bowl, how many utensils are there? Try counting on from the 8 spoons.''', 'Says ''8'', then counts the forks ''9, 10, 11, 12''.', 'Refuses to count on, insists on recounting the spoons.', 'If I hid the 8 spoons under a cloth but you knew they were there, could you still find the total?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L1_C', 'D2', 1, 'C', 'Physical storytelling', '9 small blocks, 6 large blocks', 'Build a tower of 9 small blocks. Hand them 6 large blocks. Ask: ''If we put these on top, how many blocks tall is the tower? Remember we already know the bottom is 9.''', 'Counts up from 9: ''10, 11, 12, 13, 14, 15''.', 'Takes the tower apart to count them all.', 'Why don''t we need to count the bottom blocks again?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L2_A', 'D2', 2, 'A', 'Mental / Written execution', NULL, 'Ask your child to solve 8+6. Watch how they do it. Do they use their fingers? Do they group tens?', 'Correct sum, ideally using a strategy like ''make a 10'' (8+6 -> 8+2+4 -> 10+4 = 14) rather than counting by ones.', 'Counts by ones using fingers for every problem.', 'Why does this strategy work? Could you use a different strategy and get the same answer?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L2_B', 'D2', 2, 'B', 'Mental / Written execution', NULL, 'Give your child the problem 9+7. See if they recognize that 9 is very close to 10.', 'Uses compensation: 9+7 is like 10+6, so 16.', 'Relies entirely on counting by ones.', 'If the problem was 99 + 7, how would you solve it?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L2_C', 'D2', 2, 'C', 'Mental / Written execution', NULL, 'Ask them to solve 15 + 8. Do they split the 8 into 5 and 3?', 'Solves by getting to the next decade (15+5=20, 20+3=23).', 'Makes calculation errors due to counting by ones.', 'How does finding the next ''ten'' make adding easier?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L3_A', 'D2', 3, 'A', 'Strategy comparison', NULL, 'Say: ''I need to add 48 + 35. Person A says: add 40+30, then 8+5. Person B says: take 2 from 35, give it to 48 to make 50, then add the left over 33. Which way is better? Why?''', 'Child recognizes BOTH are correct. Can explain how Person B''s ''compensation'' strategy works.', 'Thinks one person is wrong, or cannot explain Person B''s logic.', 'Is one way always better, or does it depend on the numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L3_B', 'D2', 3, 'B', 'Strategy comparison', NULL, 'Ask: ''To solve 29 + 16, someone did 30 + 16 = 46, and then added 1 to get 47. Are they right?''', 'Spots the error: they should have subtracted 1 at the end, not added 1, because they made the 29 bigger.', 'Agrees the answer is 47.', 'If you make one number bigger to make it easy to add, what do you have to do at the end?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L3_C', 'D2', 3, 'C', 'Strategy comparison', NULL, 'Say: ''Someone wrote: 14 + 17 = 10 + 10 + 4 + 7 = 20 + 11 = 31. Do you agree with how they split the numbers?''', 'Understands the decomposition of tens and ones.', 'Gets confused by breaking the numbers apart.', 'Can you split the numbers a different way? (Like 14 + 10 + 7?)', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L4_A', 'D2', 4, 'A', 'Word problem creation', NULL, 'Tell your child: ''Write a story problem that results in the equation 18 + 15 = 33. It cannot be about buying things or eating food.''', 'Creates a logically sound word problem requiring addition.', 'Creates a subtraction problem, or can''t think of a non-shopping context.', 'Read your story problem back to me. How do you know someone HAS to add to solve it?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L4_B', 'D2', 4, 'B', 'Word problem creation', NULL, 'Say: ''Create a math story for 25 + 14 = 39 about animals in a forest.''', 'Writes a story involving two groups of animals coming together.', 'Writes a story where animals leave.', 'Why does combining groups always mean addition?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L4_C', 'D2', 4, 'C', 'Word problem creation', NULL, 'Ask: ''Make up a story problem where the answer is 50, but you have to add THREE numbers together to get it.''', 'Creates a scenario with three addends that sum to 50.', 'Only uses two numbers, or the sum is incorrect.', 'How did you choose the three numbers to make exactly 50?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L1_A', 'D3', 1, 'A', 'Physical manipulation', 'Number line (drawn on floor) or physical blocks', 'Ask: ''You have 8. You need to get to 15. How many steps to get there?''', 'Understands subtraction can mean ''how much more do I need?'' and finds the difference.', 'Tries to take 15 away from 8.', 'What do you notice about where you started and where you ended up? What does ''the gap'' mean?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L1_B', 'D3', 1, 'B', 'Physical manipulation', '10 blocks of one color, 6 of another', 'Line up 10 red blocks. Line up 6 blue blocks underneath. Ask: ''How many MORE red blocks are there than blue blocks?''', 'Matches them one-to-one and counts the extra red blocks.', 'Just counts all 16 blocks.', 'Why did you just count the ones that didn''t have a partner?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L1_C', 'D3', 1, 'C', 'Physical manipulation', 'A piece of string, scissors', 'Cut a piece of string. Say: ''This was 20cm long. Now it is 12cm long. How much got cut off?''', 'Recognizes this is finding the missing part.', 'Does not understand how to find the missing length.', 'If we taped the missing piece back on, how long would it be?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L2_A', 'D3', 2, 'A', 'Written/Mental execution', NULL, 'Ask your child to solve 15-8. Can they solve it by counting up from the smaller number?', 'Uses strategies like ''counting up'' (8 + ? = 15) instead of just taking away.', 'Relies entirely on counting backward by ones.', 'Why does counting up from the smaller number give the same answer as taking away?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L2_B', 'D3', 2, 'B', 'Written/Mental execution', NULL, 'Ask them to solve 52 - 29. Suggest they make the 29 a 30 first.', 'Uses compensation: 52 - 30 = 22. But I took away one too many, so add 1 back = 23.', 'Tries to set up standard algorithm in their head and gets lost.', 'If you subtract a bigger number to make it easy, what do you do at the end?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L2_C', 'D3', 2, 'C', 'Written/Mental execution', NULL, 'Have them solve 34 - 16 by subtracting in chunks.', 'Subtracts 10 (gets 24), then subtracts 4 (gets 20), then subtracts 2 (gets 18).', 'Cannot hold the intermediate numbers in their head.', 'How do you decide what size ''chunk'' to take away first?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L3_A', 'D3', 3, 'A', 'Error detection', NULL, 'Show your child: 52 - 28. Someone wrote the answer is 36. Ask: ''What mistake did they make?''', 'Identifies that the person subtracted the smaller digit from the larger digit in both columns (5-2=3, 8-2=6) instead of regrouping.', 'Thinks 36 is correct.', 'How do you know 36 is wrong without even doing the problem yourself first?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L3_B', 'D3', 3, 'B', 'Error detection', NULL, 'Show: 40 - 15 = 35. Ask: ''Why is this wrong? What did they forget?''', 'Points out they just subtracted the tens (40-10) and brought down the 5, instead of taking 5 away from 30.', 'Cannot explain the error.', 'If you have 40 and take away MORE than 10, can the answer be in the 30s?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L3_C', 'D3', 3, 'C', 'Error detection', NULL, 'Say: ''Someone solved 82 - 79 by lining them up and borrowing. It took a long time. Was there a faster way?''', 'Recognizes the numbers are very close, so counting up (79, 80, 81, 82 -> difference of 3) is better.', 'Insists standard algorithm is the only way.', 'When are two numbers too close to bother subtracting the long way?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L4_A', 'D3', 4, 'A', 'Teaching / Reversibility', NULL, 'Ask your child: ''Can you prove to me that your subtraction answer (12-5=7) is right using addition? Teach me how they are opposites.''', 'Explains that if A - B = C, then C + B must equal A.', 'Cannot relate addition to subtraction.', 'If A - B = C, does B - A also = C? Prove it with blocks.', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L4_B', 'D3', 4, 'B', 'Teaching / Reversibility', NULL, 'Ask: ''Write a rule for how to check ANY subtraction problem to make sure the answer is right.''', 'States that adding the answer to the amount taken away must give the starting number.', 'Says ''do it again''.', 'Why does adding it back together prove it''s right?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L4_C', 'D3', 4, 'C', 'Teaching / Reversibility', NULL, 'Ask: ''Create a puzzle where someone has to figure out what was taken away: I started with 50, now I have 32. What happened?''', 'Creates a missing subtrahend problem.', 'Creates a standard subtraction problem.', 'Is finding the missing piece the same as subtraction?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L1_A', 'D4', 1, 'A', 'Visual array', 'Grid paper or a tray of organized objects (e.g., an egg carton)', 'Show an array of 4 rows and 6 columns. Ask: ''How can we count these fast without counting by 1s?''', 'Recognizes they can skip count by rows or columns.', 'Counts every single item.', 'What do you notice about the number of rows and the number in each row? Why is that important?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L1_B', 'D4', 1, 'B', 'Visual array', 'Coins or identical small items', 'Arrange 15 coins into 3 neat rows. Ask: ''Without pointing to every coin, how do we know how many there are?''', 'Notices there are 5 in each row and adds 5+5+5.', 'Breaks the array to count.', 'If we pushed the rows together, would there be the same number?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L1_C', 'D4', 1, 'C', 'Visual array', 'A building with windows, or a drawing of one', 'Look at a building with windows arranged in a grid (e.g., 3 floors, 4 windows per floor). Ask: ''How many windows are there? Use the floors to help you count.''', 'Uses skip counting to find the total windows.', 'Cannot see the grid structure.', 'Why do windows get placed like that instead of scattered randomly?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L2_A', 'D4', 2, 'A', 'Model translation', NULL, 'Ask your child to draw a picture for 4 x 6. Watch to ensure they draw equal groups or an array, not just random dots.', 'Accurately translates the expression into equal groups or an area model.', 'Draws random dots or 4 and 6 dots separately.', 'How do you know your drawing is right? Can you check it a different way?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L2_B', 'D4', 2, 'B', 'Model translation', NULL, 'Say: ''Show me 5 groups of 3 using your fingers or drawings.''', 'Accurately models the groups and counts them.', 'Cannot represent the multiplication.', 'Is 5 groups of 3 the same as 3 groups of 5? How?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L2_C', 'D4', 2, 'C', 'Model translation', NULL, 'Ask: ''Write the math equation for this: 7 bicycles, how many wheels total?''', 'Writes 7 x 2 = 14 and explains why.', 'Cannot translate the real world situation to multiplication.', 'Why didn''t you write 7 + 2?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L3_A', 'D4', 3, 'A', 'Structural property analysis', NULL, 'Ask: ''If you know 4 x 6 = 24, do you also know 6 x 4? Why? Can you prove it with your drawing?''', 'Rotates the array drawing 90 degrees to prove commutativity.', 'Does not understand that the product is the same.', 'You just showed 4x6 = 6x4. Does that work for subtraction too? (5-3 vs 3-5?)', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L3_B', 'D4', 3, 'B', 'Structural property analysis', NULL, 'Say: ''A child drew 5 groups of 4 as 5 circles, but one circle only has 3 dots. The answer they got is 19. Is this multiplication?''', 'Explains that multiplication REQUIRES equal groups, so 19 is just addition.', 'Thinks it''s a multiplication error, not a structural failure.', 'What makes multiplication special compared to just adding numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L3_C', 'D4', 3, 'C', 'Structural property analysis', NULL, 'Show: 3 x 0 = 3. Ask: ''Why is this wrong? What does 3 x 0 mean?''', 'Explains that 3 groups of nothing is nothing.', 'Believes 3 x 0 = 3, confusing it with addition.', 'If I have 0 plates with 3 cookies each, how many cookies do I have?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L4_A', 'D4', 4, 'A', 'Distributive property design', NULL, 'Ask: ''We don''t know what 7 x 8 is. But we know 5 x 8 and 2 x 8. Can we use those to find 7 x 8? Show me with a drawing.''', 'Breaks a 7x8 array into a 5x8 and a 2x8 array, demonstrating the distributive property conceptually.', 'Cannot relate the two smaller facts to the larger one.', 'Will breaking a big rectangle into smaller ones ALWAYS give you the same total? Why?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L4_B', 'D4', 4, 'B', 'Distributive property design', NULL, 'Ask: ''How can knowing 10 x 6 help you figure out 9 x 6?''', 'Explains that 9 x 6 is just 10 x 6 minus one group of 6 (60 - 6 = 54).', 'Does not understand the connection.', 'How does the ''10 times'' trick help you with ''9 times'' for any number?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L4_C', 'D4', 4, 'C', 'Distributive property design', NULL, 'Say: ''Make a hard multiplication problem using 12. Then show me how to solve it by breaking the 12 into a 10 and a 2.''', 'Sets up a problem like 12 x 7, and solves it as (10x7) + (2x7).', 'Fails to distribute the multiplication over addition.', 'Why break it into 10 and 2 instead of 6 and 6?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L1_A', 'D5', 1, 'A', 'Physical manipulation', 'Countable objects (beans, blocks), cups', 'Your child needs to divide 12 beans equally into 3 cups. Ask them to explain why the groups are equal.', 'Each cup has exactly 4 items AND child uses words like ''same'', ''equal'', ''fair''.', 'Groups are unequal OR learner cannot explain after 2 prompts.', 'Are they equal? How do you know?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L1_B', 'D5', 1, 'B', 'Physical manipulation', '15 small items, 5 plates', 'Give the child 15 items to share on 5 plates like dealing cards. ''One for you, one for you...'' Tell them to stop when they run out.', 'Deals items one by one until all plates have 3.', 'Puts random amounts on plates until they are gone.', 'Why did you put one on each plate before giving anyone a second one?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L1_C', 'D5', 1, 'C', 'Physical manipulation', '20 identical objects', 'Say: ''I have 20 objects. I want to make little piles of 4. How many piles can I make?'' (This is quotative division).', 'Makes 5 groups of 4 by pulling 4 away at a time.', 'Gets confused and tries to make 4 groups.', 'How is this different from sharing them into 4 cups?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L2_A', 'D5', 2, 'A', 'Physical manipulation with recording', NULL, 'Ask your child to divide 13 objects into 4 groups. Ask: ''What about the extra one? Is that fair?''', 'Correct partitioning in 5/5 cases, including articulating remainder as ''leftover''.', 'Tries to cut the object, or ignores the remainder.', 'If we had one more object, could we make the groups fair?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L2_B', 'D5', 2, 'B', 'Physical manipulation with recording', NULL, 'Have them draw 24 cookies shared among 6 kids. ''Draw circles for kids, put dots for cookies.''', 'Draws 6 circles with 4 dots each.', 'Draws 24 circles.', 'How did you know how many dots to put in each circle without dealing them one by one?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L2_C', 'D5', 2, 'C', 'Physical manipulation with recording', NULL, 'Ask: ''If I have 16 wheels, how many cars can I build?''', 'Writes 16 ÷ 4 = 4 cars.', 'Adds 16 + 4.', 'Is this finding the number of groups or the size of the group?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L3_A', 'D5', 3, 'A', 'Error detection + comparison', NULL, 'Set up a wrong partition (e.g., 15 objects in 4 groups: 4, 4, 4, 3). Ask the child to find the mistake and fix it. Also ask: ''Someone says 12 ÷ 3 = 5. Without counting, can you tell if that''s right or wrong? How?''', 'Identifies error, explains reasoning, uses inverse relationship (''3 x 5 = 15, not 12'').', 'Thinks 12 ÷ 3 = 5 because they don''t know multiplication facts.', 'If you know 3 x 4 = 12, what else do you automatically know about dividing?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L3_B', 'D5', 3, 'B', 'Error detection + comparison', NULL, 'Say: ''I shared 10 sweets between 2 children. One got 6, one got 4. Is that division?''', 'Explains that division must be fair/equal, so this is not division.', 'Agrees it''s division because things were split up.', 'What''s the difference between sharing and dividing?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L3_C', 'D5', 3, 'C', 'Error detection + comparison', NULL, 'Show: 14 ÷ 4 = 3 remainder 2. Say: ''Someone else got 14 ÷ 4 = 2 remainder 6. Why is the second one wrong even though 2x4+6=14?''', 'Explains that a remainder cannot be bigger than the divisor (you can make another group of 4).', 'Cannot explain why the remainder is too big.', 'If you are putting things in groups of 4, why can you never have 6 leftover?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L4_A', 'D5', 4, 'A', 'Design + Teaching', NULL, 'Say: ''Create a sharing problem for your sibling that has a remainder. Make sure it''s fair. Explain your problem and why the answer must be what it is.''', 'Creates a valid division problem, predicts the answer, explains the structure.', 'Creates a problem without a remainder, or one that cannot be solved.', 'Why do some division problems have remainders and some don''t?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L4_B', 'D5', 4, 'B', 'Design + Teaching', NULL, 'Ask: ''Design a game where players have to divide numbers by 2. What happens if they get an odd number?''', 'Designs a game with a rule for remainders (e.g., skip a turn, save the remainder).', 'Doesn''t understand odd numbers leave remainders when divided by 2.', 'What do we call numbers that can be divided by 2 with no remainder?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L4_C', 'D5', 4, 'C', 'Design + Teaching', NULL, 'Say: ''Teach me how multiplication and division are opposites. Use 5, 4, and 20.''', 'Explains that 5x4=20, 4x5=20, 20/4=5, 20/5=4 (fact family).', 'Can''t relate the operations.', 'Does division have a commutative property like multiplication (is 20/4 the same as 4/20)?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L1_A', 'D6', 1, 'A', 'Physical movement', 'Tape on floor or drawn chalk line', 'Draw a line with marks 0 to 10. Ask your child to stand on 3. Then say: ''Walk to 7. How many steps did you take?''', 'Child counts the *steps* (the spaces between numbers), not the tick marks.', 'Child counts the numbers themselves (3, 4, 5, 6, 7 = 5).', 'What''s the difference between counting the marks and counting the jumps? Which one tells you the distance?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L1_B', 'D6', 1, 'B', 'Physical movement', 'A long ruler or tape measure', 'Show a measuring tape. Ask: ''If a bug walks from the 10cm mark to the 15cm mark, how far did it walk?''', 'Sees the space between 10 and 15 is 5 units.', 'Says 15cm.', 'Does it matter where the bug started?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L1_C', 'D6', 1, 'C', 'Physical movement', 'Floor tiles or paving stones', 'Have them stand on a tile. Call it ''Tile 0''. Ask: ''Jump 4 tiles forward. Now jump 2 tiles back. Where are you?''', 'Models 4 - 2 = 2 on the physical grid.', 'Gets lost making the jumps.', 'How is jumping forward and backward like math?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L2_A', 'D6', 2, 'A', 'Abstract representation', NULL, 'Ask your child to place 48 and 60 on a blank line with 50 in the middle. Check if the distance makes sense.', 'Numbers are in the correct order, and the proportional distance is roughly accurate.', 'Places 48 to the right of 50, or puts 60 right next to 50.', 'Why does the spacing between numbers matter? What happens if you make the spaces uneven?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L2_B', 'D6', 2, 'B', 'Abstract representation', NULL, 'Draw an open number line. Ask: ''Solve 34 + 12 using jumps on this line.''', 'Starts at 34, jumps 10 to 44, jumps 2 to 46.', 'Tries to draw 46 individual tick marks.', 'Why is it better to jump by 10s than by 1s?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L2_C', 'D6', 2, 'C', 'Abstract representation', NULL, 'Draw a line with marks at 0, 10, 20. Ask them to point to approximately where 17 is.', 'Points closer to 20 than to 10.', 'Points in the exact middle or close to 10.', 'How did you know it was closer to the 20?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L3_A', 'D6', 3, 'A', 'Error detection', NULL, 'Show a number line where the distance from 0 to 10 is the same size as the distance from 10 to 12. Ask: ''What is wrong with this picture?''', 'Recognizes the scale is broken (10 steps shouldn''t take the same space as 2 steps).', 'Thinks it''s fine because the numbers are in order.', 'Why is a broken scale confusing when you try to solve a math problem?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L3_B', 'D6', 3, 'B', 'Error detection', NULL, 'Show a number line that goes 10, 20, 30, 50, 60. Ask: ''What''s missing and why is that a problem?''', 'Notices 40 is missing, creating a jump of 20 instead of 10.', 'Doesn''t notice the skip.', 'Can a number line skip numbers if the spaces change size?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L3_C', 'D6', 3, 'C', 'Error detection', NULL, 'Say: ''Someone tried to solve 50 - 20 by jumping forward instead of backward. Does that work?''', 'Understands that distance is distance, so starting at 20 and jumping to 50 gives the same answer (30).', 'Thinks subtraction MUST move left.', 'Is ''taking away'' the only way to subtract?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L4_A', 'D6', 4, 'A', 'System creation', NULL, 'Ask: ''Design a number line that only shows multiples of 5 (0, 5, 10...). Use it to show someone how to solve 15 + 10.''', 'Creates a consistent scale stepping by 5s and models an operation on it.', 'Draws a line with 1s but only labels the 5s.', 'How does changing the scale (what each tick mark means) make math easier for big numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L4_B', 'D6', 4, 'B', 'System creation', NULL, 'Ask: ''Draw a number line that goes backward, starting at 100 and ending at 0. Use it to solve 80 - 15.''', 'Draws the line correctly with 100 on the left and 0 on the right (unconventional but valid).', 'Cannot conceptualize a reversed line.', 'Does math still work if the line goes the other way? Why?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L4_C', 'D6', 4, 'C', 'System creation', NULL, 'Say: ''Create a thermometer using a number line. Make sure it has numbers below zero.''', 'Extends the number line to the left of zero with negative numbers.', 'Stops at zero.', 'What do the numbers on the other side of zero mean?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L1_A', 'D7', 1, 'A', 'Observation', '3 rocks, 4 leaves', 'Show 3 rocks and 4 leaves. Count them (7). Now swap them: show 4 leaves and 3 rocks. Count them. Ask: ''Did the total change? Does the order matter?''', 'Recognizes order doesn''t change the sum (Commutative property).', 'Thinks the new order makes a new amount.', 'If we had 100 rocks and 2 leaves, which is easier to start counting from?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L1_B', 'D7', 1, 'B', 'Observation', '3 types of objects (e.g. 2 spoons, 3 forks, 4 cups)', 'Put 2 spoons and 3 forks in one group, 4 cups in another. Count total. Then put 2 spoons alone, and 3 forks + 4 cups together. Count total. Ask: ''Did the total change?''', 'Notices grouping differently doesn''t change the sum (Associative property).', 'Believes moving the items changes the total.', 'Does it matter who is grouped with who, if they all go in the same pot?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L1_C', 'D7', 1, 'C', 'Observation', 'Blocks or legos', 'Build a 2x5 rectangle of blocks. Ask how many. Then turn it 90 degrees to be 5x2. Ask how many. ''Did I add any blocks? Did the total change?''', 'Sees that 2x5 is the same amount as 5x2.', 'Has to recount the blocks when it turns.', 'Does standing a rectangle up make it bigger than laying it down?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L2_A', 'D7', 2, 'A', 'Relational thinking', NULL, 'Give your child the problem 2 + 7 + 8. Ask: ''Which two numbers should you add first to be fast?''', 'Uses properties (associative/commutative) to group 2+8=10, then add 7 to get 17.', 'Works left to right (2+7=9, 9+8=17), missing the structure.', 'Why is finding a 10 always a good first step?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L2_B', 'D7', 2, 'B', 'Relational thinking', NULL, 'Say: ''I know 8 x 5 is 40. What is 5 x 8?''', 'Answers 40 immediately without calculating.', 'Tries to count by 5s eight times.', 'If you forget what 7 x 3 is, what other problem could you solve to find the answer?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L2_C', 'D7', 2, 'C', 'Relational thinking', NULL, 'Show the problem (4 + 6) + 5 = 15. Ask: ''If I move the parentheses to 4 + (6 + 5), what will the answer be?''', 'Knows it will still be 15.', 'Calculates 6+5=11, then 11+4=15 to check.', 'Why do parentheses matter in math, and why do they NOT change the answer in addition?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L3_A', 'D7', 3, 'A', 'Boundary testing', NULL, 'Ask: ''You know 5 + 3 is the same as 3 + 5. Is 5 - 3 the same as 3 - 5? Let''s check with blocks.''', 'Discovers that subtraction is NOT commutative.', 'Assumes the rule applies to everything.', 'Why does order matter when you take away, but not when you put together?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L3_B', 'D7', 3, 'B', 'Boundary testing', NULL, 'Ask: ''Is 10 ÷ 2 the same as 2 ÷ 10?''', 'Understands that sharing 10 things among 2 people is very different from sharing 2 things among 10 people.', 'Thinks the answer is 5 both ways.', 'Which operation is division like: addition or subtraction? (Order matters for both subtraction and division).', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L3_C', 'D7', 3, 'C', 'Boundary testing', NULL, 'Say: ''Someone wrote: (10 - 5) - 2 = 10 - (5 - 2). Let''s solve both sides. Do they equal the same thing?''', 'Calculates left side as 3, right side as 7. Realizes the associative property does NOT work for subtraction.', 'Assumes they must be equal without checking.', 'Why can''t you just move parentheses around in a subtraction problem?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L4_A', 'D7', 4, 'A', 'Generalization', NULL, 'Ask: ''Can you write a rule about adding? Something that is ALWAYS true for any numbers you ever find?''', 'States a rule like ''You can always switch the numbers when adding and get the same answer.''', 'Writes a specific math fact like 2+2=4.', 'Can you prove your rule works for a giant number, like 1,000,000 + 1?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);